import{j as a,b as e,c as t,a9 as n}from"./chunks/framework.CFGK5tmi.js";const S=JSON.parse('{"title":"Spring","description":"","frontmatter":{},"headers":[],"relativePath":"backend/java/Spring.md","filePath":"backend/java/Spring.md","lastUpdated":null}'),r={name:"backend/java/Spring.md"},o=n('<h1 id="spring" tabindex="-1">Spring <a class="header-anchor" href="#spring" aria-label="Permalink to &quot;Spring&quot;">​</a></h1><h2 id="基础" tabindex="-1">基础 <a class="header-anchor" href="#基础" aria-label="Permalink to &quot;基础&quot;">​</a></h2><p><strong>Spring 是一个轻量级、非入侵式的控制反转 (IoC) 和面向切面 (AOP) 的框架。</strong></p><h2 id="ioc" tabindex="-1">IoC <a class="header-anchor" href="#ioc" aria-label="Permalink to &quot;IoC&quot;">​</a></h2><p><strong>IoC</strong>（控制反转，Inversion of Control）：由容器来控制对象的生命周期和对象之间的关系。控制对象声明周期的不再是引用它的对象，而是容器。</p><p>为什么要使用IoC？</p><p>比如MVC中，controller A调用service B，那就要手动new一个service对象，即A与B之间就产生了依赖。有了IoC之后，对象A不用去new一个B对象了，只需要从容器中取出。</p><div style="display:none;" data-pagefind-meta="base64:JTdCJTIyZGF0ZSUyMiUzQTE3MTUzMjYxNDMwODclN0Q="></div>',8),i=[o];function s(c,d,p,l,_,h){return e(),t("div",null,i)}const f=a(r,[["render",s]]);export{S as __pageData,f as default};
